@Override
    public boolean test(MethodRef t) {
        Boolean suspendable = suspendables.get(t);
        if (suspendable == null) {
            throw new IllegalArgumentException("Method " + t.getName() + t.getDesc() + " not found");
        }
        return suspendable;
    }
